import { toGregorian, toEthiopian } from '../src/index';

describe('Ethiopian Calendar Converter', () => {
    // 1. Enkutatash (Ethiopian New Year)
    test('Ethiopian 2017,1,1 should convert to Gregorian 2024,9,11 (Enkutatash)', () => {
        expect(toGregorian(2017, 1, 1)).toEqual({ year: 2024, month: 9, day: 11 });
    });

    test('Gregorian 2024,9,11 should convert to Ethiopian 2017,1,1 (Enkutatash inverse)', () => {
        expect(toEthiopian(2024, 9, 11)).toEqual({ year: 2017, month: 1, day: 1 });
    });

    // 2. Ethiopian Christmas (Genna)
    test('Ethiopian 2017,4,29 (Genna) should convert to Gregorian 2025,1,7', () => {
        expect(toGregorian(2017, 4, 29)).toEqual({ year: 2025, month: 1, day: 7 });
    });

    test('Gregorian 2025,1,7 should convert to Ethiopian 2017,4,29 (Genna inverse)', () => {
        expect(toEthiopian(2025, 1, 7)).toEqual({ year: 2017, month: 4, day: 29 });
    });

    // 3. Date in the middle of the Ethiopian year
    test('Ethiopian 2017,7,15 should convert to Gregorian 2025,3,24', () => {
        expect(toGregorian(2017, 7, 15)).toEqual({ year: 2025, month: 3, day: 24 });
    });

    test('Gregorian 2025,3,24 should convert to Ethiopian 2017,7,15 (inverse)', () => {
        expect(toEthiopian(2025, 3, 24)).toEqual({ year: 2017, month: 7, day: 15 });
    });

    // 4. Date in Pagume (13th month) - Non-leap Ethiopian year (2017 EC has 5 Pagume days)
    test('Ethiopian 2017,13,5 (Pagume 5) should convert to Gregorian 2025,9,10', () => {
        expect(toGregorian(2017, 13, 5)).toEqual({ year: 2025, month: 9, day: 10 });
    });

    test('Gregorian 2025,9,10 should convert to Ethiopian 2017,13,5 (Pagume 5 inverse)', () => {
        expect(toEthiopian(2025, 9, 10)).toEqual({ year: 2017, month: 13, day: 5 });
    });

    // 5. Ethiopian Leap Year (2015 EC is a leap year → Pagume has 6 days)
    test('Ethiopian 2015,13,6 (Pagume 6) should convert to Gregorian 2023,9,10', () => {
        expect(toGregorian(2015, 13, 6)).toEqual({ year: 2023, month: 9, day: 10 });
    });

    test('Gregorian 2023,9,10 should convert to Ethiopian 2015,13,6 (Pagume 6 inverse)', () => {
        expect(toEthiopian(2023, 9, 10)).toEqual({ year: 2015, month: 13, day: 6 });
    });

    // 6. Victory of Adwa (Yekatit 23) in an Ethiopian leap year (2015 EC)
    test('Ethiopian 2015,6,23 should convert to Gregorian 2023,3,2', () => {
        expect(toGregorian(2015, 6, 23)).toEqual({ year: 2023, month: 3, day: 2 });
    });

    test('Gregorian 2023,3,2 should convert to Ethiopian 2015,6,23 (Victory of Adwa inverse)', () => {
        expect(toEthiopian(2023, 3, 2)).toEqual({ year: 2015, month: 6, day: 23 });
    });

    // 7. Gregorian Leap Day (Feb 29, 2024)
    test('Gregorian 2024,2,29 should convert to Ethiopian 2016,6,21', () => {
        expect(toEthiopian(2024, 2, 29)).toEqual({ year: 2016, month: 6, day: 21 });
    });

    test('Ethiopian 2016,6,21 should convert to Gregorian 2024,2,29 (Leap Day inverse)', () => {
        expect(toGregorian(2016, 6, 21)).toEqual({ year: 2024, month: 2, day: 29 });
    });

    // 8. Historical Enkutatash (non-leap Gregorian year)
    test('Ethiopian 1999,1,1 should convert to Gregorian 2006,9,11', () => {
        expect(toGregorian(1999, 1, 1)).toEqual({ year: 2006, month: 9, day: 11 });
    });

    test('Gregorian 2006,9,11 should convert to Ethiopian 1999,1,1 (Historical Enkutatash inverse)', () => {
        expect(toEthiopian(2006, 9, 11)).toEqual({ year: 1999, month: 1, day: 1 });
    });

    // 9. Next leap year in the cycle (2019 EC)
    test('Ethiopian 2019,13,6 (Pagume 6) should convert to Gregorian 2027,9,11', () => {
        expect(toGregorian(2019, 13, 6)).toEqual({ year: 2027, month: 9, day: 11 });
    });
});